try:
    L = int(input("Enter Likelihood (1-3): "))
    I = int(input("Enter Impact (1-3): "))
    if L not in (1, 2, 3) or I not in (1, 2, 3):
        print("Invalid input")
    else:
        score = L * I
        if score <= 2:
            priority = "Low"
            action = "Monitor"
        elif score <= 4:
            priority = "Medium"
            action = "Fix Soon"
        else:
            priority = "High"
            action = "Fix Now"
        print(f"Risk Score = {score} | Priority = {priority} | Action = {action}")
except ValueError:
    print("Invalid input (please enter integers only)")

def apply_pwm(value: int):
    print("PWM applied:", value)

def get_safe_speed():
    raw = input("Enter motor speed (0-255): ").strip()
    speed = 0
    try:
        candidate = int(raw)
        if 0 <= candidate <= 255:
            speed = candidate
        else:
            print("Unsafe speed -> using safe default (0)")
    except ValueError:
        print("Invalid input -> using safe default (0)")
    return speed

speed = get_safe_speed()
apply_pwm(speed)

